# -*- coding: utf-8 -*-
import pytest
# import pytest_asyncio
from typing import List
from .taskScheduler import InterActiveMonitor
# import asyncio

@pytest.mark.asyncio
async def test_successful_process_execution():
    """
    测试正常流程：子进程正确执行并返回预期输出。
    """
    command = ["python", "-c", "import sys; print(sys.stdin.read().upper(), end='')"]
    input_data = "hello"
    monitor = InterActiveMonitor(command, input_data)
    proc, stdout, stderr = await monitor.run()

    # 验证返回码、输出和错误
    assert proc.returncode == 0
    assert stdout.decode().strip() == "HELLO"
    assert stderr == b""

@pytest.mark.asyncio
async def test_process_with_errors():
    """
    测试子进程执行出错的情况（如命令参数错误）。
    """
    command = ["python", "-c", "import sys; print('Error', file=sys.stderr); sys.exit(1)"]
    monitor = InterActiveMonitor(command, "")
    proc, stdout, stderr = await monitor.run()

    # 验证返回码和错误输出
    assert proc.returncode == 1
    assert stdout == b""
    assert "Error" in stderr.decode()

@pytest.mark.asyncio
async def test_empty_input_data():
    """
    测试输入数据为空的情况。
    """
    command = ["python", "-c", "print('Done')"]
    monitor = InterActiveMonitor(command, "")
    proc, stdout, stderr = await monitor.run()

    assert proc.returncode == 0
    assert stdout.decode().strip() == "Done"
    assert stderr == b""

@pytest.mark.asyncio
async def test_invalid_command():
    """
    测试无效命令（如不存在的可执行文件）。
    """
    command = ["non_existent_command"]
    monitor = InterActiveMonitor(command, "input")
    with pytest.raises(ValueError):
        await monitor.run()